<template><div class="border rounded-lg p-2" :style="{borderLeft:'3px solid '+unit.status_color}"><div class="flex justify-between"><div class="text-xs font-semibold">{{ unit.name }} <span class="text-slate-400">(Suite)</span></div><div class="font-bold text-sm">{{ unit.number }}</div></div><div class="text-[11px] text-slate-500 mt-2">👤 {{ unit.capacity }} &nbsp; 🛏 {{ unit.beds }} &nbsp; 🛁 {{ unit.baths }}</div><button class="w-full mt-3 border rounded py-1 text-xs font-semibold" @click="onAction">{{ unit.action }}</button><button class="w-full mt-2 border rounded py-1 text-xs font-semibold bg-[#e95a54] text-white border-none shadow-sm hover:bg-orange-600 transition-all" @click="$router.push({name: 'new-reservation', query: {unit_id: unit.id}})">Reserve Now</button></div></template>
<script setup>const props=defineProps({unit:Object}); const emit=defineEmits(['action']); const onAction=()=>emit('action',{unit_id:props.unit.id,reservation_id:1,action:props.unit.action});</script>
